import{_ as s,o as t,c as e,a2 as i}from"./chunks/framework.M-AdQQii.js";const c=JSON.parse('{"title":"3.7 宗师披风","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 宗师披风最早是用公会贡献换的，改版后在荣誉商店用荣誉换，是绑定的装备。 下图红框内的披风升级后就是宗师披风： 宗师披风是绑定的，且无任何手段转移到同账号下其他角色。 宗师披风根据对应的职业","frontmatter":{"title":"3.7 宗师披风","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 宗师披风最早是用公会贡献换的，改版后在荣誉商店用荣誉换，是绑定的装备。 下图红框内的披风升级后就是宗师披风： 宗师披风是绑定的，且无任何手段转移到同账号下其他角色。 宗师披风根据对应的职业","outline":"deep"},"headers":[],"relativePath":"grandmaster/3-7.md","filePath":"grandmaster/3-7.md","lastUpdated":1782387794000}'),u={name:"grandmaster/3-7.md"};function g(l,a,r,o,p,d){return t(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="_3-7-宗师披风" tabindex="-1">3.7 宗师披风 <a id="s262-24dafa9c"></a> <a class="header-anchor" href="#_3-7-宗师披风" aria-label="Permalink to &quot;3.7 宗师披风 &lt;a id=&quot;s262-24dafa9c&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_3-7-1-什么是宗师披风" tabindex="-1">3.7.1 什么是宗师披风 <a id="s263-8471173b"></a> <a class="header-anchor" href="#_3-7-1-什么是宗师披风" aria-label="Permalink to &quot;3.7.1 什么是宗师披风 &lt;a id=&quot;s263-8471173b&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师披风最早是用公会贡献换的，改版后在荣誉商店用荣誉换，是绑定的装备。</p><p>下图红框内的披风升级后就是宗师披风：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2675.jpeg" alt="图示：3.7.1 什么是宗师披风" loading="lazy"></figure><h2 id="_3-7-2-宗师披风能否交易或者转移给小号角色" tabindex="-1">3.7.2 宗师披风能否交易或者转移给小号角色？ <a id="s264-0f34469e"></a> <a class="header-anchor" href="#_3-7-2-宗师披风能否交易或者转移给小号角色" aria-label="Permalink to &quot;3.7.2 宗师披风能否交易或者转移给小号角色？ &lt;a id=&quot;s264-0f34469e&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师披风是绑定的，且无任何手段转移到同账号下其他角色。</p><h2 id="_3-7-3-宗师披风的种类" tabindex="-1">3.7.3 宗师披风的种类 <a id="s265-fabe1cd5"></a> <a class="header-anchor" href="#_3-7-3-宗师披风的种类" aria-label="Permalink to &quot;3.7.3 宗师披风的种类 &lt;a id=&quot;s265-fabe1cd5&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师披风根据对应的职业属性可以分为以下5 种：</p><p>①风向披风：弓手</p><p>②骄傲披风：坦克</p><p>③庇护披风：奶妈</p><p>④闪光披风：刺客</p><p>⑤安息披风：施法法师</p><h2 id="_3-7-4-宗师披风的觉醒" tabindex="-1">3.7.4 宗师披风的觉醒 <a id="s266-b17f86cc"></a> <a class="header-anchor" href="#_3-7-4-宗师披风的觉醒" aria-label="Permalink to &quot;3.7.4 宗师披风的觉醒 &lt;a id=&quot;s266-b17f86cc&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师披风觉醒卷轴需要在勇士制作台制作。</p><p>勇士制作台可以在势力主城、光芒海岸、领地势力总部找到。如下图：</p><p>各阶段觉醒卷轴材料如下图：</p><p>披风觉醒失败后有概率受损，受损后需要以下卷轴修复：</p><p>公会每日任务烛台可以获得该卷轴碎片。</p><p>宗师披风觉醒一般都需要很高加成概率才能成功，伊弗尼尔的继承者们，准备好你的肝吧。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2683.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2684.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2691.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2692.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2693.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2694.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2695.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2696.jpeg" alt="图示：3.7.4 宗师披风的觉醒" loading="lazy"></figure><h2 id="_3-7-5-宗师披风经验的获取" tabindex="-1">3.7.5 宗师披风经验的获取 <a id="s267-7f08e4b2"></a> <a class="header-anchor" href="#_3-7-5-宗师披风经验的获取" aria-label="Permalink to &quot;3.7.5 宗师披风经验的获取 &lt;a id=&quot;s267-7f08e4b2&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师披风可以用在亡灵箱子开出来的披风喂、签到送的经验石头喂、刷领地给的石头喂、原大陆石盘喂。除了亡灵箱子的披风，建议喂给石盘，将石盘喂到太初0 经验再喂给披风，这样子如果跳经验的话可以省很多的肝，经验石头喂石盘跳经验概率也更高。</p><p>刚刚制作出来的未拆封的石盘是可以交易的，拆封了就绑定不可以交易了。</p><p>石盘太初0 经验和满经验喂给披风都是10000 经验。</p><p>石盘材料如下：</p><p>喂披风和石盘都需要刷领地中立动物怪，会掉经验石头，如下图：</p><p>开这两个石头不需要劳动力，因此不吃各种熟练度还有晨露的施法加成。开出来的经验石头有部分重叠，但是蓝色的开出来的品质更高，白色的有几率开出2 个披风石头（一个低品质的和一个高品质的）。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2702.jpeg" alt="图示：3.7.5 宗师披风经验的获取" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2703.jpeg" alt="图示：3.7.5 宗师披风经验的获取" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2704.jpeg" alt="图示：3.7.5 宗师披风经验的获取" loading="lazy"></figure><h2 id="_3-7-6-宗师披风的词条" tabindex="-1">3.7.6 宗师披风的词条 <a id="s268-3783888f"></a> <a class="header-anchor" href="#_3-7-6-宗师披风的词条" aria-label="Permalink to &quot;3.7.6 宗师披风的词条 &lt;a id=&quot;s268-3783888f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>各个职业的披风都有一个固定的词条，只受披风阶段影响。各个职业披风还有一个二选一绿色词条，受品质和经验值影响。所有披风另外有4 个通用蓝色词条，受品质和经验值影响。在下图替换界面即可查看词条，以及满经验时的词条属性。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2709.jpeg" alt="图示：3.7.6 宗师披风的词条" loading="lazy"></figure>',43)])])}const h=s(u,[["render",g]]);export{c as __pageData,h as default};
